var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아얏!","JPN":"痛っ！","ENG":"Ouch!","TWN":"啊呀！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"귀신 같은 소리 하네. 하여간, 잠시도 한눈을 팔 수가 없다니까.","JPN":"幽霊だなんてよく言うよ。ったく、少しも目が離せないんだから。","ENG":"No, I'm not a ghost. Geez, I knew I should have kept an eye on you two.","TWN":"鬼叫什麼，妳們這樣讓我怎麼放心。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"아프다고...... 머리 좀 그만 때려, 라우라.","JPN":"痛いってば……頭を叩くのはやめてよ、ラウラ。","ENG":"Ow... That hurts... Stop hitting me on the head, Laura.","TWN":"好疼啊……別打我的頭，蘿拉。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"대체 여긴 어떻게 들어온 거야? 낙오되지 않게 바짝 쫓아오라는 말은 벌써 잊어버렸어?","JPN":"いったいここにはどうやって入ったんだ？　はぐれないように、しっかりついてこいと言っただろ？","ENG":"How did you even end up here? I told you to keep up so you won't get left behind, didn't I?","TWN":"妳們是怎麼進來的？我不是說過一定要跟緊我，不要掉隊嗎？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아무리 우리 관리하에 있다고 해도 여긴 이면세계야.","JPN":"妾たちの管理下にあるとはいえ、ここは裏世界だ。","ENG":"Although this place may be under our management, it's still the Counterside.","TWN":"即使這裡是我們的管轄範圍，但畢竟是異界。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"쉽사리 방심했다간 어떤 일을 당할지 모른다고.","JPN":"油断したらどんな目に遭うかわからない。","ENG":"There's no telling what will happen if you let down your guard.","TWN":"一不小心就可能會出事。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"나, 나도 그 정도는 알고 있어! 하지만 신입이......","JPN":"わ、私だってそのくらいわかってる！　でも新入りが……","ENG":"I-I know! But the newbie here...","TWN":"我、我也知道！不過新人她……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"신입이?","JPN":"新入りが？","ENG":"Newbie?","TWN":"新人？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"여긴...... 어디예요? 이면세계에 있다는 유적 같은 건가요?","JPN":"ここは……どこですか？　裏世界の遺跡みたいなものでしょうか？","ENG":"Where... are we? Is this some kind of ruin, the type they say can be found in the Counterside?","TWN":"這裡……是哪裡？是異界裡的遺跡嗎？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"여긴 발푸르기스 성이야.","JPN":"ここはヴァルプルギス城だ。","ENG":"This is Walpurgis Castle.","TWN":"這裡是魔女之夜城。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"발푸르기스 성?","JPN":"ヴァルプルギス城？","ENG":"Walpurgis Castle?","TWN":"魔女之夜城？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......그리고 출입 금지구역이지.","JPN":"……そして、立入禁止区域だ。","ENG":"And it's off-limits.","TWN":"……而且是禁止出入的區域。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"관심 가져 봐야 너희들에게 좋을 것 하나 없으니까 잊어버려.","JPN":"興味を持ったところで得することは何もないから忘れてしまえ。","ENG":"Just forget about this place. You have nothing to gain from getting nosy about it.","TWN":"不要多問，知道了對你們沒什麼好處，還是忘掉吧。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"하지만......","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"거 참 말 많네. 오늘 갓 들어온 견습이 왜 이리 귀찮게 굴어?","JPN":"ったくうるさいな。今日入った見習いがどこまで面倒をかければ気が済むんだ？","ENG":"Enough with the buts already! You just got here today, dang it!","TWN":"沒完沒了了，剛來的見習哪來那麼多問題？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"더 이상 캐묻지 마. 다 이유가 있어서 금지 구역으로 정해 둔 거니까.","JPN":"これ以上聞き出そうとするな。すべて理由があって禁止区域にしたんだから。","ENG":"When I say it's off-limits, there's a good reason for it. So stop asking.","TWN":"別好奇了，被定為禁區都是有原因的。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"계속 물어 보면 하루 종일 재채기가 나오는 저주를 걸어 버리겠어.","JPN":"しつこく聞いてくるなら、一日中くしゃみが止まらない呪いをかけるぞ。","ENG":"If you keep asking, I'll curse you so you'll sneeze all day.","TWN":"再問我就下詛咒，讓你們整天都打噴嚏。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};